}): Promise<GitHubProjectItemsPage> {
	const response = await fetch("https://api.github.com/graphql", {
		method: "POST",
		headers: {
			Accept: "application/vnd.github+json",
			Authorization: `Bearer ${input.env.GITHUB_TOKEN}`,
			"X-GitHub-Api-Version": "2022-11-28",
