				after: input.after,
			},
		}),
	});

	if (!response.ok) {
		throw new Error(
			`GitHub GraphQL request failed with status ${response.status}.`,
		);
	}

	const payload = (await response.json()) as GitHubProjectItemsGraphQLResponse;

