			workerRunId: null,
			classification: checkSummary.classification,
			skippedFreshDuplicate: true,
			checkSummary,
		};
	}

	const workerRun = await createWorkerRun(client, {
		workItemId: input.workItemId,
		kind: "post_pr_curator",
		status: "completed",
