}

export async function listWorkItemGraph(
	client: Client,
	workItemId: string,
): Promise<WorkItemGraph> {
	const [runsResult, decisionsResult, artifactsResult, linksResult] =
		await Promise.all([
			client.execute({
				sql: `
				SELECT
					id,
					work_item_id,
					kind,
					status,
					claim_token,
					metadata_json,
					work_item_snapshot_json,
					created_at,
					updated_at,
					started_at,
					finished_at
				FROM worker_runs
				WHERE work_item_id = ?
				ORDER BY created_at DESC
			`,
				args: [workItemId],
			}),
			client.execute({
				sql: `
				SELECT
					id,
					work_item_id,
					worker_run_id,
					phase,
					outcome,
					deterministic,
					policy_version,
					policy_rule_id,
					evidence_json,
					next_worker_kind,
					next_action,
					created_at,
					updated_at
				FROM decisions
				WHERE work_item_id = ?
				ORDER BY created_at DESC
			`,
				args: [workItemId],
			}),
			client.execute({
				sql: `
				SELECT
					id,
					work_item_id,
					worker_run_id,
					kind,
					external_id,
					external_url,
					snapshot_json,
					metadata_json,
					created_at,
					updated_at
				FROM artifacts
				WHERE work_item_id = ?
				ORDER BY created_at DESC
			`,
				args: [workItemId],
			}),
			client.execute({
				sql: `
				SELECT
					id,
					work_item_id,
					from_node_type,
					from_node_id,
					to_node_type,
					to_node_id,
					relation,
					metadata_json,
					created_at
				FROM links
				WHERE work_item_id = ?
				ORDER BY created_at ASC
			`,
				args: [workItemId],
			}),
		]);

	return {
		workItemId,
		workerRuns: runsResult.rows.map(mapWorkerRun),
		decisions: decisionsResult.rows.map(mapDecision),
